var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"처음부터 내 입장은 감시자라고 밝혔는데도...... 당신은 다른 직원들과 나를 똑같이 취급하더군.","JPN":"私の立場はあくまで監視者だと、初めから言っていたというのに……お前は、私を他の社員と同じように扱っていたな。","ENG":"I told you when I joined your company that I came here to keep an eye on you, but you still treat me like any other employee.","TWN":"從一開始我就說我是監視者……但你對我就像對待其他員工一樣。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"당신도 참 별난 사람이야.","JPN":"お前は実に変わったやつだ。","ENG":"I have to say you're quite eccentric.","TWN":"你也真是個怪人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"언제 자기를 벨지도 모르는 상대와 아무렇지 않게 인사를 주고 받는 것도......","JPN":"いつ斬りかかってくるかわからない相手と、無邪気に挨拶を交わしたと思えば……","ENG":"You exchange greetings with me as if there's nothing wrong, when there's no telling when I might cut you down...","TWN":"不管是若無其事地跟不知道什麼時候會殺死自己的對手問好……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그리고 이제는 또 호위 한 명 없이 만나자고 하는 것도.","JPN":"挙句の果てに、護衛の一人も付けずに面会を申し出るとはな。","ENG":"And now you ask to see me without any bodyguards?","TWN":"還是現在不帶一名護衛，就來跟我見面。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"예전부터 감시하면서 눈치는 챘어.","JPN":"お前をずっと監視していて、気付かなかったわけではない。","ENG":"I did notice something while I was monitoring you.","TWN":"從開始監視的時候我就發現了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"어떤 사람이든 서슴없이 대할 수 있는 점이 당신이 가진 무기겠지.","JPN":"どんな相手とも気負わずに付き合える。それはお前の持つ武器なのだろう。","ENG":"Your ability to treat everyone the same is probably your greatest weapon.","TWN":"你和所有人都能自然地相處，這應該就是你的武器吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"물론 그게 당신 천성은 아니란 것도 알아.","JPN":"もちろん、それが天性のものではないことくらいはわかる。","ENG":"At the same time, I know you weren't always like this.","TWN":"當然，我也知道那並不是你的天性。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"너무 오래되서 흐릿해지긴 했어도, 당신이 어떤 고난을 겪고 지금에 다다랐는지는 볼 수 있거든.","JPN":"あまりにも昔なのでおぼろげにしか見えないが、私には、お前がどのような苦境を乗り越えて今に至ったのかが見えている。","ENG":"Although it's rather faint from the passage of time, I can get a glimpse of the suffering you went through to get to where you are today.","TWN":"儘管因為時間久遠而有些模糊了，但我仍能看到你過去所經歷的苦難。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"......말했잖아. 이 눈에는 가끔 보이지 말아야 할 게 보인다고.","JPN":"……言ったはずだろう？　この目には、時々見えてはいけないものが見えると。","ENG":"Like I said... Sometimes this eye sees things that should not be visible.","TWN":"……我有說過吧，這隻眼睛偶爾能看到不該看的東西。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"과거, 기억, 감정...... 자질구레해도 사용하기에 따라선 쓸모있는 것들이지.","JPN":"過去、記憶、感情……そんな雑多なものも、使いようによっては役に立つものだ。","ENG":"The past, memories, emotions... They may seem petty, but they can be quite useful depending on how you use them.","TWN":"過去、記憶、情感……雖然都是些零碎的東西，但有時會有用些用處。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"새삼스럽게 감탄한 척 하지 마. 이 안대는 멋만으로 찬 게 아니라고 누누이 말했을 텐데.","JPN":"今さら感嘆してみせても遅い。この眼帯は格好をつけているわけではないと、前々から言っていただろう？","ENG":"Oh, don't act so impressed. I've told you many times that this eye patch isn't there just for show. ","TWN":"別裝出一副佩服的樣子，我應該說過很多次，這眼罩可不是為了耍酷才戴的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"그래도 잘 어울린다는 말은 고맙군. 흠흠.","JPN":"しかし、よく似合っていると言ってくれるのは……素直に嬉しいな。","ENG":"But it feels nice to hear that it looks good on me. *Clears throat*","TWN":"不過，還是很謝謝你說它適合我，哼哼。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"금발 원숭이처럼 아무것도 모르고 설치는 애송이들은 질색이지만, 당신처럼 예정된 시련에 맞서려는 사람은 싫어하지 않아.","JPN":"あの金髪ザルのように見境なく暴れる青二才にはほとほとウンザリしているが、お前のように、定められた試練に立ち向かおうとする人間は嫌いじゃない。","ENG":"I hate kids running wild, without a clue what they're doing, like that blonde monkey, but I actually like people struggling to stand against their fate, like you.","TWN":"我討厭和金髮猴一樣愛亂衝的小鬼，但不討厭你這種敢正面接受試煉的人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEEJISOO_SIX_NULL_NULL","text":{"KOREA":"......나도, 비슷한 처지니까.","JPN":"……私もまた、似たような境遇だからな。","ENG":"You remind me of myself.","TWN":"……因為我的處境也跟你差不多。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJISOO_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};